-- Run this file after selecting the target database in your MySQL client.
-- On shared hosting, the database is usually created for you and CREATE DATABASE/USE may be denied.

CREATE TABLE roles (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, name VARCHAR(80) NOT NULL UNIQUE, slug VARCHAR(100) NOT NULL UNIQUE, description TEXT, is_system TINYINT(1) DEFAULT 0, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE permissions (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, module VARCHAR(80) NOT NULL, name VARCHAR(120) NOT NULL, slug VARCHAR(140) NOT NULL UNIQUE, description TEXT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, INDEX idx_permissions_module(module)) ENGINE=InnoDB;
CREATE TABLE users (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, name VARCHAR(160) NOT NULL, email VARCHAR(190) NOT NULL UNIQUE, password_hash VARCHAR(255) NOT NULL, primary_role VARCHAR(80) DEFAULT 'Employee', status ENUM('pending','active','suspended','locked') DEFAULT 'pending', email_verified_at TIMESTAMP NULL, last_login_at TIMESTAMP NULL, failed_login_attempts INT DEFAULT 0, locked_until TIMESTAMP NULL, remember_token VARCHAR(120), preferences JSON, deleted_at TIMESTAMP NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE user_roles (user_id BIGINT UNSIGNED NOT NULL, role_id BIGINT UNSIGNED NOT NULL, PRIMARY KEY(user_id, role_id), FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE, FOREIGN KEY(role_id) REFERENCES roles(id) ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE role_permissions (role_id BIGINT UNSIGNED NOT NULL, permission_id BIGINT UNSIGNED NOT NULL, PRIMARY KEY(role_id, permission_id), FOREIGN KEY(role_id) REFERENCES roles(id) ON DELETE CASCADE, FOREIGN KEY(permission_id) REFERENCES permissions(id) ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE branches (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, name VARCHAR(140) NOT NULL, code VARCHAR(40) UNIQUE, address TEXT, timezone VARCHAR(80) DEFAULT 'Asia/Kolkata', is_active TINYINT(1) DEFAULT 1) ENGINE=InnoDB;
CREATE TABLE departments (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, branch_id BIGINT UNSIGNED NULL, name VARCHAR(140) NOT NULL, code VARCHAR(40) UNIQUE, manager_id BIGINT UNSIGNED NULL, FOREIGN KEY(branch_id) REFERENCES branches(id) ON DELETE SET NULL) ENGINE=InnoDB;
CREATE TABLE teams (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, department_id BIGINT UNSIGNED NOT NULL, name VARCHAR(140) NOT NULL, lead_id BIGINT UNSIGNED NULL, FOREIGN KEY(department_id) REFERENCES departments(id) ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE designations (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, department_id BIGINT UNSIGNED NULL, title VARCHAR(140) NOT NULL, level VARCHAR(40), FOREIGN KEY(department_id) REFERENCES departments(id) ON DELETE SET NULL) ENGINE=InnoDB;
CREATE TABLE employees (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, user_id BIGINT UNSIGNED UNIQUE, employee_code VARCHAR(60) NOT NULL UNIQUE, full_name VARCHAR(180) NOT NULL, gender VARCHAR(40), date_of_birth DATE, blood_group VARCHAR(10), nationality VARCHAR(80), marital_status VARCHAR(40), email VARCHAR(190) NOT NULL, phone VARCHAR(40), emergency_contact JSON, addresses JSON, identity_numbers JSON, bank_details JSON, department_id BIGINT UNSIGNED, team_id BIGINT UNSIGNED, designation_id BIGINT UNSIGNED, reporting_manager_id BIGINT UNSIGNED NULL, joining_date DATE NOT NULL, probation_ends_on DATE NULL, confirmation_date DATE NULL, total_experience_months INT DEFAULT 0, skills JSON, education JSON, custom_fields JSON, employment_status ENUM('active','inactive','probation','notice','terminated','resigned') DEFAULT 'active', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE SET NULL, FOREIGN KEY(department_id) REFERENCES departments(id) ON DELETE SET NULL, FOREIGN KEY(team_id) REFERENCES teams(id) ON DELETE SET NULL, FOREIGN KEY(designation_id) REFERENCES designations(id) ON DELETE SET NULL, INDEX idx_employee_status(employment_status), INDEX idx_employee_department(department_id)) ENGINE=InnoDB;
CREATE TABLE interns (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, user_id BIGINT UNSIGNED NULL, intern_code VARCHAR(60) NOT NULL UNIQUE, full_name VARCHAR(180) NOT NULL, college VARCHAR(180), university VARCHAR(180), branch VARCHAR(120), semester VARCHAR(40), internship_type ENUM('paid','unpaid') DEFAULT 'paid', stipend DECIMAL(12,2) DEFAULT 0, department_id BIGINT UNSIGNED, team_id BIGINT UNSIGNED, mentor_id BIGINT UNSIGNED NULL, reporting_manager_id BIGINT UNSIGNED NULL, joining_date DATE, ending_date DATE, completion_percentage DECIMAL(5,2) DEFAULT 0, status ENUM('draft','active','ongoing','completed','converted','terminated') DEFAULT 'draft', evaluation JSON, FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE SET NULL, FOREIGN KEY(department_id) REFERENCES departments(id) ON DELETE SET NULL, FOREIGN KEY(team_id) REFERENCES teams(id) ON DELETE SET NULL) ENGINE=InnoDB;
CREATE TABLE shifts (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, name VARCHAR(120), starts_at TIME, ends_at TIME, grace_minutes INT DEFAULT 0) ENGINE=InnoDB;
CREATE TABLE attendance (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, user_id BIGINT UNSIGNED NOT NULL, attendance_date DATE NOT NULL, check_in DATETIME NULL, check_out DATETIME NULL, status ENUM('present','absent','late','half_day','holiday','leave','wfh') NOT NULL, shift_id BIGINT UNSIGNED NULL, overtime_minutes INT DEFAULT 0, UNIQUE KEY uniq_attendance(user_id, attendance_date), FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE, FOREIGN KEY(shift_id) REFERENCES shifts(id) ON DELETE SET NULL) ENGINE=InnoDB;
CREATE TABLE attendance_logs (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, attendance_id BIGINT UNSIGNED, event_type VARCHAR(50), event_at DATETIME, source VARCHAR(80), metadata JSON, FOREIGN KEY(attendance_id) REFERENCES attendance(id) ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE leave_requests (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, user_id BIGINT UNSIGNED NOT NULL, leave_type VARCHAR(80), starts_on DATE, ends_on DATE, days DECIMAL(5,2), reason TEXT, status ENUM('pending','approved','rejected','cancelled') DEFAULT 'pending', current_approver_id BIGINT UNSIGNED NULL, FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE, INDEX idx_leave_status(status)) ENGINE=InnoDB;
CREATE TABLE approval_requests (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, approvable_type VARCHAR(120), approvable_id BIGINT UNSIGNED, requested_by BIGINT UNSIGNED, status ENUM('pending','approved','rejected') DEFAULT 'pending', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE projects (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, name VARCHAR(180), code VARCHAR(60) UNIQUE, owner_id BIGINT UNSIGNED, status VARCHAR(60), starts_on DATE, ends_on DATE) ENGINE=InnoDB;
CREATE TABLE tasks (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, project_id BIGINT UNSIGNED NULL, title VARCHAR(220), description TEXT, assignee_id BIGINT UNSIGNED, priority ENUM('low','medium','high','critical') DEFAULT 'medium', status ENUM('todo','in_progress','review','done','cancelled') DEFAULT 'todo', due_at DATETIME, progress TINYINT UNSIGNED DEFAULT 0, FOREIGN KEY(project_id) REFERENCES projects(id) ON DELETE SET NULL, INDEX idx_tasks_status(status)) ENGINE=InnoDB;
CREATE TABLE salaries (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, employee_id BIGINT UNSIGNED NOT NULL, effective_from DATE, ctc DECIMAL(14,2), components JSON, FOREIGN KEY(employee_id) REFERENCES employees(id) ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE payroll (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, employee_id BIGINT UNSIGNED, payroll_month CHAR(7), gross DECIMAL(14,2), deductions DECIMAL(14,2), net_pay DECIMAL(14,2), status ENUM('draft','approved','paid') DEFAULT 'draft', payslip_path VARCHAR(255), FOREIGN KEY(employee_id) REFERENCES employees(id) ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE document_categories (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, name VARCHAR(120), retention_days INT NULL, requires_expiry TINYINT(1) DEFAULT 0) ENGINE=InnoDB;
CREATE TABLE documents (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, owner_type VARCHAR(80), owner_id BIGINT UNSIGNED, category_id BIGINT UNSIGNED, title VARCHAR(180), file_path VARCHAR(255), mime_type VARCHAR(120), version INT DEFAULT 1, expires_on DATE NULL, uploaded_by BIGINT UNSIGNED, visibility VARCHAR(40) DEFAULT 'restricted', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY(category_id) REFERENCES document_categories(id) ON DELETE SET NULL) ENGINE=InnoDB;
CREATE TABLE letter_templates (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, type VARCHAR(120), name VARCHAR(180), body MEDIUMTEXT, placeholders JSON, is_active TINYINT(1) DEFAULT 1) ENGINE=InnoDB;
CREATE TABLE letters (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, template_id BIGINT UNSIGNED, owner_type VARCHAR(80), owner_id BIGINT UNSIGNED, letter_number VARCHAR(80) UNIQUE, rendered_html MEDIUMTEXT, pdf_path VARCHAR(255), generated_by BIGINT UNSIGNED, status ENUM('draft','generated','signed','void') DEFAULT 'draft', FOREIGN KEY(template_id) REFERENCES letter_templates(id) ON DELETE SET NULL) ENGINE=InnoDB;
CREATE TABLE certificates (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, owner_type VARCHAR(80), owner_id BIGINT UNSIGNED, certificate_number VARCHAR(80) UNIQUE, verification_token VARCHAR(120) UNIQUE, template JSON, pdf_path VARCHAR(255), issued_by BIGINT UNSIGNED, issued_at TIMESTAMP NULL) ENGINE=InnoDB;
CREATE TABLE job_openings (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, title VARCHAR(180), department_id BIGINT UNSIGNED, status VARCHAR(60), description TEXT, FOREIGN KEY(department_id) REFERENCES departments(id) ON DELETE SET NULL) ENGINE=InnoDB;
CREATE TABLE candidates (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, job_opening_id BIGINT UNSIGNED, name VARCHAR(180), email VARCHAR(190), phone VARCHAR(40), resume_path VARCHAR(255), stage VARCHAR(80), source VARCHAR(80), FOREIGN KEY(job_opening_id) REFERENCES job_openings(id) ON DELETE SET NULL) ENGINE=InnoDB;
CREATE TABLE interviews (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, candidate_id BIGINT UNSIGNED, interviewer_id BIGINT UNSIGNED, round_name VARCHAR(120), scheduled_at DATETIME, feedback JSON, decision VARCHAR(60), FOREIGN KEY(candidate_id) REFERENCES candidates(id) ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE performance_reviews (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, employee_id BIGINT UNSIGNED, cycle VARCHAR(80), reviewer_id BIGINT UNSIGNED, ratings JSON, goals JSON, status VARCHAR(60), FOREIGN KEY(employee_id) REFERENCES employees(id) ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE assets (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, asset_tag VARCHAR(80) UNIQUE, type VARCHAR(80), name VARCHAR(160), serial_number VARCHAR(120), condition_status VARCHAR(80), assigned_to BIGINT UNSIGNED NULL, issued_on DATE NULL, returned_on DATE NULL) ENGINE=InnoDB;
CREATE TABLE notifications (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, user_id BIGINT UNSIGNED, channel VARCHAR(40), title VARCHAR(180), body TEXT, read_at TIMESTAMP NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE announcements (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, title VARCHAR(180), body TEXT, audience JSON, published_at TIMESTAMP NULL) ENGINE=InnoDB;
CREATE TABLE holidays (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, branch_id BIGINT UNSIGNED NULL, name VARCHAR(160), holiday_date DATE, FOREIGN KEY(branch_id) REFERENCES branches(id) ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE company_settings (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, setting_key VARCHAR(120) UNIQUE, setting_value JSON) ENGINE=InnoDB;
CREATE TABLE system_settings (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, setting_key VARCHAR(120) UNIQUE, setting_value JSON) ENGINE=InnoDB;
CREATE TABLE login_history (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, user_id BIGINT UNSIGNED NULL, email VARCHAR(190), ip_address VARCHAR(64), user_agent VARCHAR(255), status VARCHAR(40), logged_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE SET NULL) ENGINE=InnoDB;
CREATE TABLE audit_logs (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, actor_id BIGINT UNSIGNED NULL, action VARCHAR(140), auditable_type VARCHAR(120), auditable_id BIGINT UNSIGNED, old_values JSON, new_values JSON, ip_address VARCHAR(64), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, INDEX idx_audit_action(action), INDEX idx_audit_subject(auditable_type, auditable_id)) ENGINE=InnoDB;
CREATE TABLE activity_logs (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, user_id BIGINT UNSIGNED NULL, activity VARCHAR(180), metadata JSON, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB;
